            "starterCode": "import socket\n\n# Целевой домен корпорации\ntarget_domain = \"hackme-bank.com\"\n\nprint(f\"[*] OSINT: Инициируем пассивную разведку для домена: {target_domain}\")\n\ntry:\n    # Функция socket.gethostbyname() инициирует DNS-резолвинг\n    # На уровне ОС она формирует UDP пакет на порт 53 к локальному DNS-серверу\n    target_ip = \n    \n    print(f\"[+] Успех! DNS Resolution прошел успешно.\")\n    print(f\"[+] A-запись (IP-адрес цели): {target_ip}\")\n    print(\"[*] IP-адрес получен. В реальной атаке мы бы также запросили MX и TXT записи.\")\n    \nexcept socket.gaierror:\n    print(\"[-] Ошибка: DNS NXDOMAIN (Non-Existent Domain).\")"
